EnumWindowsProc      = ctypes.WINFUNCTYPE(ctypes.c_bool, ctypes.c_void_p, ctypes.c_void_p)
GetWindowTextW       = user32.GetWindowTextW
GetWindowTextLengthW = user32.GetWindowTextLengthW
GetClassNameW        = user32.GetClassNameW
ShowWindow           = user32.ShowWindow
IsIconic             = user32.IsIconic
IsWindowVisible      = user32.IsWindowVisible
SetForegroundWindow  = user32.SetForegroundWindow
GetKeyState          = user32.GetKeyState
keybd_event          = user32.keybd_event
SetWindowPos         = user32.SetWindowPos
GetWindowRect        = user32.GetWindowRect
GetSystemMetrics     = user32.GetSystemMetrics
GetForegroundWindow  = user32.GetForegroundWindow
GetWindowThreadProcessId = user32.GetWindowThreadProcessId
PostMessageW         = user32.PostMessageW
GetWindowLongW       = user32.GetWindowLongW
SetWindowLongW       = user32.SetWindowLongW

GWL_EXSTYLE      = -20
WS_EX_LAYERED    = 0x00080000
WS_EX_TOOLWINDOW = 0x00000080
WS_EX_APPWINDOW  = 0x00040000
LWA_ALPHA        = 0x00000002
SW_HIDE         = 0
SW_MINIMIZE     = 6
SW_RESTORE      = 9
SW_SHOW         = 5
VK_NUMLOCK      = 0x90
KEYEVENTF_KEYUP = 0x0002
SWP_NOSIZE      = 0x0001
SWP_NOMOVE      = 0x0002
SWP_SHOWWINDOW  = 0x0040
HWND_NOTOPMOST  = -2
DWMWA_CLOAKED   = 14
WM_CLOSE        = 0x0010
PROCESS_QUERY_LIMITED_INFORMATION = 0x1000


class RECT(ctypes.Structure):
    _fields_ = [("left", ctypes.c_long), ("top", ctypes.c_long),
                ("right", ctypes.c_long), ("bottom", ctypes.c_long)]


class LASTINPUTINFO(ctypes.Structure):
    _fields_ = [("cbSize", wintypes.UINT), ("dwTime", wintypes.DWORD)]


# === Структуры для SendInput (автовставка единиц) ===
# Важно: union должен содержать ВСЕ варианты ввода (mouse/keyboard/hardware),
# иначе sizeof(INPUT) будет меньше ожидаемого и SendInput молча вернёт 0.
class MOUSEINPUT(ctypes.Structure):
    _fields_ = [("dx", wintypes.LONG), ("dy", wintypes.LONG),
                ("mouseData", wintypes.DWORD), ("dwFlags", wintypes.DWORD),
                ("time", wintypes.DWORD),
                ("dwExtraInfo", ctypes.POINTER(ctypes.c_ulong))]

class KEYBDINPUT(ctypes.Structure):
    _fields_ = [("wVk", wintypes.WORD),
                ("wScan", wintypes.WORD),
                ("dwFlags", wintypes.DWORD),
                ("time", wintypes.DWORD),
                ("dwExtraInfo", ctypes.POINTER(ctypes.c_ulong))]

class HARDWAREINPUT(ctypes.Structure):
    _fields_ = [("uMsg", wintypes.DWORD),
                ("wParamL", wintypes.WORD), ("wParamH", wintypes.WORD)]

class _INPUT_UNION(ctypes.Union):
    _fields_ = [("mi", MOUSEINPUT),
                ("ki", KEYBDINPUT),
                ("hi", HARDWAREINPUT)]

class INPUT(ctypes.Structure):
    _anonymous_ = ("_u",)
    _fields_ = [("type", wintypes.DWORD), ("_u", _INPUT_UNION)]

INPUT_KEYBOARD = 1
KEYEVENTF_KEYDOWN = 0x0000
# KEYEVENTF_KEYUP уже определён выше
VK_CONTROL = 0x11
VK_V = 0x56
VK_C = 0x43

# Параметры SendInput по MSDN
user32.SendInput.argtypes = [wintypes.UINT, ctypes.POINTER(INPUT), ctypes.c_int]
user32.SendInput.restype = wintypes.UINT


