def log(msg: str):
    try:
        ts = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        LOGS_DIR.mkdir(parents=True, exist_ok=True)
        with open(LOG_FILE, "a", encoding="utf-8") as f:
            f.write(f"[{ts}] {msg}\n")
    except Exception:
        pass



# ---------------------------------------------------------------------------
# Startup profiling shared by shell/calculator modules
# ---------------------------------------------------------------------------
_STARTUP_PROFILE_T0 = time.perf_counter()
_STARTUP_PROFILE_LAST = _STARTUP_PROFILE_T0

def startup_profile(label: str) -> None:
    """Единый профиль запуска: общий ms от импорта functions.py и delta от предыдущей точки.

    Пишет в logs/startup_profile.log и debug.log. Используется для разборки
    тяжёлых этапов старта без циклического импорта calc_numlock_tray.pyw.
    """
    global _STARTUP_PROFILE_LAST
    try:
        now = time.perf_counter()
        total_ms = int((now - _STARTUP_PROFILE_T0) * 1000)
        delta_ms = int((now - _STARTUP_PROFILE_LAST) * 1000)
        _STARTUP_PROFILE_LAST = now
        line = f"STARTUP +{total_ms:05d} ms Δ{delta_ms:05d} ms | {label}"
        try:
            log(line)
        except Exception:
            pass
        try:
            LOGS_DIR.mkdir(parents=True, exist_ok=True)
            with open(LOGS_DIR / "startup_profile.log", "a", encoding="utf-8") as f:
                f.write(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] {line}\n")
        except Exception:
            pass
    except Exception:
        pass

