def load_embedded_icon() -> QtGui.QIcon:
    """Загружает иконку из вшитого base64."""
    try:
        raw = base64.b64decode(ICON_B64)
        pix = QtGui.QPixmap()
        if pix.loadFromData(raw, "ICO"):
            return QtGui.QIcon(pix)
    except Exception:
        pass
    # Фоллбэк — красный квадрат
    pix = QtGui.QPixmap(32, 32)
    pix.fill(QtGui.QColor("#e05"))
    return QtGui.QIcon(pix)


# ---------------------------------------------------------------------------
# WinAPI-хелперы: ввод (Ctrl+V)
# ---------------------------------------------------------------------------
def _send_ctrl_v():
    """
    Отправляет Ctrl+V через SendInput.
    Возвращает True, если все 4 события приняты системой.
    """
    arr = (INPUT * 4)()
    # Ctrl down
    arr[0].type = INPUT_KEYBOARD
    arr[0].ki.wVk = VK_CONTROL
    # V down
    arr[1].type = INPUT_KEYBOARD
    arr[1].ki.wVk = VK_V
    # V up
    arr[2].type = INPUT_KEYBOARD
    arr[2].ki.wVk = VK_V
    arr[2].ki.dwFlags = KEYEVENTF_KEYUP
    # Ctrl up
    arr[3].type = INPUT_KEYBOARD
    arr[3].ki.wVk = VK_CONTROL
    arr[3].ki.dwFlags = KEYEVENTF_KEYUP
    sent = user32.SendInput(4, arr, ctypes.sizeof(INPUT))
    if sent != 4:
        err = ctypes.get_last_error()
        log(f"SendInput sent={sent}/4, GetLastError={err}, "
            f"sizeof(INPUT)={ctypes.sizeof(INPUT)}")
        return False
    return True




def _send_ctrl_c():
    """
    Отправляет Ctrl+C через SendInput.
    Возвращает True, если все 4 события приняты системой.
    Используется автокопированием результата из активного окна калькулятора.
    """
    arr = (INPUT * 4)()
    # Ctrl down
    arr[0].type = INPUT_KEYBOARD
    arr[0].ki.wVk = VK_CONTROL
    # C down
    arr[1].type = INPUT_KEYBOARD
    arr[1].ki.wVk = VK_C
    # C up
    arr[2].type = INPUT_KEYBOARD
    arr[2].ki.wVk = VK_C
    arr[2].ki.dwFlags = KEYEVENTF_KEYUP
    # Ctrl up
    arr[3].type = INPUT_KEYBOARD
    arr[3].ki.wVk = VK_CONTROL
    arr[3].ki.dwFlags = KEYEVENTF_KEYUP
    sent = user32.SendInput(4, arr, ctypes.sizeof(INPUT))
    if sent != 4:
        err = ctypes.get_last_error()
        log(f"SendInput Ctrl+C sent={sent}/4, GetLastError={err}, "
            f"sizeof(INPUT)={ctypes.sizeof(INPUT)}")
        return False
    return True

def _force_foreground(hwnd) -> bool:
    """
    Пытается сделать hwnd активным окном, обходя защиту от SetForegroundWindow.
    Техника AttachThreadInput, которая работает в большинстве случаев.
    """
    try:
        if not hwnd:
            return False
        if IsIconic(hwnd):
            ShowWindow(hwnd, SW_RESTORE)
        # Прямая попытка — обычно работает, т.к. наш процесс сам foreground
        if user32.SetForegroundWindow(hwnd):
            return True
        # Fallback: привязываем input-очереди
        cur_fg = GetForegroundWindow()
        if not cur_fg:
            return False
        fg_tid = user32.GetWindowThreadProcessId(cur_fg, None)
        our_tid = kernel32.GetCurrentThreadId()
        if fg_tid and fg_tid != our_tid:
            user32.AttachThreadInput(our_tid, fg_tid, True)
            try:
                user32.BringWindowToTop(hwnd)
                user32.SetForegroundWindow(hwnd)
            finally:
                user32.AttachThreadInput(our_tid, fg_tid, False)
        return GetForegroundWindow() == hwnd
    except Exception as e:
        log(f"_force_foreground error: {e}")
        return False


# ---------------------------------------------------------------------------
# WinAPI-хелперы: текст / класс окна
# ---------------------------------------------------------------------------
def _get_text(hwnd) -> str:
    n = GetWindowTextLengthW(hwnd)
    if not n:
        return ""
    buf = ctypes.create_unicode_buffer(n + 1)
    GetWindowTextW(hwnd, buf, n + 1)
    return buf.value


def _get_class(hwnd) -> str:
    buf = ctypes.create_unicode_buffer(256)
    GetClassNameW(hwnd, buf, 256)
    return buf.value


def _exe_basename_of_hwnd(hwnd) -> str:
    """Возвращает basename exe процесса, которому принадлежит окно."""
    try:
        pid = wintypes.DWORD()
        GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
        if not pid.value:
            return ""
        h_proc = kernel32.OpenProcess(PROCESS_QUERY_LIMITED_INFORMATION, False, pid.value)
        if not h_proc:
            return ""
        try:
            buf = ctypes.create_unicode_buffer(512)
            size = wintypes.DWORD(512)
            if kernel32.QueryFullProcessImageNameW(h_proc, 0, buf, ctypes.byref(size)):
                return Path(buf.value).name.lower()
        finally:
            kernel32.CloseHandle(h_proc)
    except Exception:
        pass
    return ""


# ---------------------------------------------------------------------------
# WinAPI-хелперы: окна калькулятора / поиск по exe
# ---------------------------------------------------------------------------
def find_calc_hwnd():
    result = {"hwnd": None}
    def _cb(hwnd, _):
        if (_get_class(hwnd) == CALC_CLASS and _get_text(hwnd) and
                any(t.lower() in _get_text(hwnd).lower() for t in CALC_TITLES)):
            result["hwnd"] = hwnd
            return False
        return True
    user32.EnumWindows(EnumWindowsProc(_cb), 0)
    return result["hwnd"]


def find_hwnd_by_exe(exe_basename: str):
    """
    Ищет видимое top-level окно, принадлежащее процессу с заданным basename
    exe (например, 'windows_calculator.exe'). Пропускает окна без заголовка.
    """
    exe_basename = (exe_basename or "").lower()
    if not exe_basename:
        return None
    result = {"hwnd": None}
    IsWindowVisible = user32.IsWindowVisible
    GetWindow = user32.GetWindow
    GW_OWNER = 4

    def _cb(hwnd, _):
        try:
            if not IsWindowVisible(hwnd):
                return True
            # Пропускаем дочерние окна-«owner» (чтобы брать главное)
            if GetWindow(hwnd, GW_OWNER):
                return True
            if not GetWindowTextLengthW(hwnd):
                return True
            if _exe_basename_of_hwnd(hwnd) == exe_basename:
                result["hwnd"] = hwnd
                return False
        except Exception:
            pass
        return True
    user32.EnumWindows(EnumWindowsProc(_cb), 0)
    return result["hwnd"]


def is_cloaked(hwnd) -> bool:
    try:
        v = ctypes.c_int(0)
        dwmapi.DwmGetWindowAttribute(hwnd, DWMWA_CLOAKED, ctypes.byref(v), ctypes.sizeof(v))
        return v.value != 0
    except Exception:
        return False


def get_rect(hwnd) -> RECT:
    r = RECT()
    GetWindowRect(hwnd, ctypes.byref(r))
    return r


def apply_opacity(hwnd, pct: int):
    pct = max(0, min(100, pct))
    if pct <= 30:
        opacity = pct / 30.0 * 70.0
    else:
        opacity = 70.0 + (pct - 30) / 70.0 * 30.0
    alpha = max(0, min(255, int(opacity / 100.0 * 255)))
    style = user32.GetWindowLongW(hwnd, GWL_EXSTYLE)
    user32.SetWindowLongW(hwnd, GWL_EXSTYLE, style | WS_EX_LAYERED)
    user32.SetLayeredWindowAttributes(hwnd, 0, alpha, LWA_ALPHA)


# ---------------------------------------------------------------------------
# WinAPI-хелперы: foreground / idle
# Используются и трекером Pro Secure, и базовой логикой.
# ---------------------------------------------------------------------------
def get_foreground_exe() -> str:
    """Имя exe активного окна. Только имя файла, без пути и заголовка."""
    try:
        hwnd = GetForegroundWindow()
        if not hwnd:
            return ""
        pid = wintypes.DWORD()
        GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
        h_proc = kernel32.OpenProcess(PROCESS_QUERY_LIMITED_INFORMATION, False, pid.value)
        if not h_proc:
            return ""
        try:
            buf = ctypes.create_unicode_buffer(512)
            size = wintypes.DWORD(512)
            if kernel32.QueryFullProcessImageNameW(h_proc, 0, buf, ctypes.byref(size)):
                return Path(buf.value).name.lower()
        finally:
            kernel32.CloseHandle(h_proc)
    except Exception:
        pass
    return ""


def get_idle_seconds() -> float:
    """Сколько секунд назад было последнее событие ввода (WinAPI-опрос, не хук)."""
    try:
        lii = LASTINPUTINFO()
        lii.cbSize = ctypes.sizeof(LASTINPUTINFO)
        if user32.GetLastInputInfo(ctypes.byref(lii)):
            tick = kernel32.GetTickCount()
            return max(0, (tick - lii.dwTime) / 1000.0)
    except Exception:
        pass
    return 0.0


def get_foreground_hwnd() -> int:
    try:
        return GetForegroundWindow()
    except Exception:
        return 0


# ---------------------------------------------------------------------------
# StayOpenMenu — меню, не закрывающееся по клику на action с флагом stay_open
# ---------------------------------------------------------------------------
class StayOpenMenu(QMenu):
    """
    QMenu с двумя режимами «не закрывать»:

    1. Action имеет property('stay_open', True) — не закрывается при любом клике.
    2. Меню в режиме `keep_open_on_modifier=True` — ПКМ и Shift+ЛКМ выполняют
       action без закрытия меню; обычный ЛКМ — стандартное поведение.

    Режим (2) включается через `setKeepOpenOnModifier(True)`.
    """

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self._keep_open_on_modifier = False

    def setKeepOpenOnModifier(self, enabled: bool) -> None:
        self._keep_open_on_modifier = bool(enabled)

    def keepOpenOnModifier(self) -> bool:
        return self._keep_open_on_modifier

    def _action_at_pos(self, pos):
        """Возвращает action под точкой — даже если activeAction() уже сброшен."""
        try:
            return self.actionAt(pos)
        except Exception:
            return None

    def _trigger_silently(self, action) -> bool:
        """Триггерит action без закрытия меню. Возвращает True, если сработало."""
        if not action or not action.isEnabled() or action.menu() is not None:
            return False
        try:
            # Для checkable actions сами переключаем состояние — так делает QMenu сам.
            if action.isCheckable():
                action.setChecked(not action.isChecked())
            # Помечаем, что триггер идёт «без закрытия» — слушатели action могут
            # использовать это, чтобы решить, имеет ли смысл слать Ctrl+V в чужое окно.
            self.setProperty("stay_open_triggered", True)
            try:
                action.trigger()
            finally:
                self.setProperty("stay_open_triggered", False)
        except Exception:
            return False
        return True

    def mousePressEvent(self, event):
        # ПКМ перехватываем целиком на press: иначе Qt откроет контекстное меню
        # по умолчанию или сбросит подсветку. Действие — на release.
        if (self._keep_open_on_modifier
                and event.button() == Qt.RightButton):
            event.accept()
            return
        super().mousePressEvent(event)

    def mouseReleaseEvent(self, event):
        # Режим 1: индивидуальный stay_open на active action.
        active = self.activeAction()
        if (active and active.isEnabled() and active.menu() is None
                and active.property("stay_open")):
            active.trigger()
            return

        # Режим 2: ПКМ или Shift+ЛКМ — выполнить и не закрывать.
        if self._keep_open_on_modifier:
            mods = event.modifiers()
            btn = event.button()
            is_right = (btn == Qt.RightButton)
            is_shift_left = (btn == Qt.LeftButton and (mods & Qt.ShiftModifier))
            if is_right or is_shift_left:
                # Для ПКМ activeAction() может быть None (пресс не активировал).
                target = active or self._action_at_pos(event.pos())
                if self._trigger_silently(target):
                    event.accept()
                    return
                # Если триггер не получился (например, separator/disabled) —
                # просто гасим событие, не давая super() закрыть меню по ПКМ.
                if is_right:
                    event.accept()
                    return

        super().mouseReleaseEvent(event)

    def contextMenuEvent(self, event):
        # Не показывать системное контекстное меню поверх нашего popup'а.
        if self._keep_open_on_modifier:
            event.accept()
            return
        super().contextMenuEvent(event)


class SmartMenu(StayOpenMenu):
    """Меню, которое раскрывается влево, если находится в правой половине экрана."""
    def popup(self, pos):
        screen_geo = QGuiApplication.primaryScreen().geometry()
        menu_width = self.sizeHint().width()
        # Если точка pos.x + ожидаемая ширина меню выходит за середину экрана,
        # раскрываем влево
        if pos.x() + menu_width > screen_geo.width() // 2:
            pos.setX(pos.x() - menu_width)
        super().popup(pos)



# ---------------------------------------------------------------------------
# Native titlebar/theme helpers for small dialogs
# ---------------------------------------------------------------------------
def _colorref(hex_color: str) -> int:
    try:
        h = str(hex_color or "").strip().lstrip("#")
        if len(h) != 6:
            return 0
        r = int(h[0:2], 16); g = int(h[2:4], 16); b = int(h[4:6], 16)
        return (b << 16) | (g << 8) | r
    except Exception:
        return 0


def _apply_native_titlebar(hwnd: int, dark: bool, caption_color: str, text_color: str) -> None:
    if not sys.platform.startswith("win") or not hwnd:
        return
    try:
        dwm = ctypes.windll.dwmapi
    except Exception:
        return
    dark_value = ctypes.c_int(1 if dark else 0)
    for attr in (20, 19):
        try:
            dwm.DwmSetWindowAttribute(
                wintypes.HWND(hwnd), ctypes.c_uint(attr),
                ctypes.byref(dark_value), ctypes.sizeof(dark_value),
            )
        except Exception:
            pass
    for attr, color in ((35, caption_color), (36, text_color)):
        try:
            value = ctypes.c_int(_colorref(color))
            dwm.DwmSetWindowAttribute(
                wintypes.HWND(hwnd), ctypes.c_uint(attr),
                ctypes.byref(value), ctypes.sizeof(value),
            )
        except Exception:
            pass


def _apply_dialog_theme_from_app(dlg, app) -> None:
    try:
        import styles as _styles
        mode = getattr(app, "interface_theme", None)
        p = _styles.active_palette(mode)
        dlg.setStyleSheet(_styles.DIALOG_QSS)
        _apply_native_titlebar(int(dlg.winId()), p.name == "dark", p.window_bg, p.text_primary)
    except Exception:
        try:
            dlg.setStyleSheet(DIALOG_QSS)
        except Exception:
            pass
